static void ExcelAutomationWithCleanup(Args _args)
{
    // Declare all COM objects at method scope for cleanup access
    SysExcelApplication     excelApp;
    SysExcelWorkbooks       workbooks;
    SysExcelWorkbook        workbook;
    SysExcelWorksheets      worksheets;
    SysExcelWorksheet       worksheet;
    SysExcelCells           cells;

    // Working variables
    FileName                fileName;
    boolean                 excelStarted = false;
    int                     row;
    str                     cellValue;

    // Initialize filename
    fileName = "C:\\Temp\\TestData.xlsx";

    try
    {
        // Create Excel application instance
        excelApp = SysExcelApplication::construct();
        excelStarted = true;

        // Configure Excel for optimal performance and no user interaction
        excelApp.visible(false);              // Run invisibly
        excelApp.displayAlerts(false);        // Suppress all Excel dialogs

        // Get workbooks collection and open file
        workbooks = excelApp.workbooks();
        workbook = workbooks.open(fileName);

        // Access first worksheet
        worksheets = workbook.worksheets();
        worksheet = worksheets.itemFromNum(1);  // 1-based index
        cells = worksheet.cells();

        // Example: Read data from Excel
        row = 1;
        cellValue = cells.item(row, 1).value().bStr();  // Read A1

        while (cellValue)  // Continue until empty cell
        {
            info(strFmt("Row %1: %2", row, cellValue));

            // Process the data here
            // ... your business logic ...

            row++;
            cellValue = cells.item(row, 1).value().bStr();
        }

        // Save changes if needed
        if (!workbook.saved())
        {
            workbook.saveAs(fileName);  // Or use different name
        }
    }
    catch (Exception::Error)
    {
        error("Excel automation failed - check file path and Excel installation");
    }
    catch (Exception::Break)
    {
        warning("Excel import cancelled by user");
    }
    catch (Exception::CLRError)
    {
        error("Excel COM error: " + AifUtil::getClrErrorMessage());
    }
    catch
    {
        error("Unexpected error during Excel automation");
    }

    // CRITICAL: Cleanup happens OUTSIDE try/catch in AX 2009
    // This ensures it runs regardless of how we exit the try block
    if (excelStarted && excelApp)
    {
        // Close workbook if it exists
        if (workbook)
        {
            // Close without saving changes (pass false to save)
            workbook.comObject().Close(false);
        }

        // Quit Excel application
        excelApp.quit();

        // Explicitly null the reference to release COM object
        excelApp = null;
    }

    // Force garbage collection to ensure COM cleanup
    System.GC::Collect();
    System.GC::WaitForPendingFinalizers();
}
